// ============================================================
// FECAPA Hoquei Patins — Frontend App
// Loads data.json (generated by scraper) and renders the UI
// ============================================================

const SHIELD_BASE = "https://sidgad.cloud/fecapa/images/logos_clubes/";
const STORAGE_KEY = "hoquei_fecapa_fav";
const DATA_URL    = "./data.json";

// ── State ─────────────────────────────────────────────────────
const state = {
  data:           null,
  activeCategory: "ALL",
  searchQuery:    "",
  selectedComp:   null,
  selectedTeam:   null,   // filter calendar/classif to one team
  activeTab:      "summary",
  saved:          JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]"),
};

// ── DOM refs ──────────────────────────────────────────────────
const $loading     = document.getElementById("screen-loading");
const $picker      = document.getElementById("screen-picker");
const $detail      = document.getElementById("screen-detail");
const $loadingNote = document.getElementById("loading-note");
const $searchInput = document.getElementById("search-input");
const $filterTabs  = document.getElementById("filter-tabs");
const $pickerBody  = document.getElementById("picker-body");
const $heroSeason  = document.getElementById("hero-season");
const $heroSub     = document.getElementById("hero-sub");
const $backBtn     = document.getElementById("back-btn");
const $compName    = document.getElementById("detail-comp-name");
const $compMeta    = document.getElementById("detail-meta");

// ── Helpers ───────────────────────────────────────────────────
function shield(clubId, alt = "") {
  if (!clubId) return `<span class="team-shield-placeholder"></span>`;
  return `<img class="team-shield" src="${SHIELD_BASE}${clubId}.gif" alt="${alt}" onerror="this.style.display='none'"/>`;
}

function shieldLg(clubId, alt = "") {
  if (!clubId) return `<span style="width:36px;height:36px;display:inline-block;background:#eef;border-radius:8px"></span>`;
  return `<img style="width:36px;height:36px;object-fit:contain;background:#f5f7ff;border-radius:8px;padding:2px" src="${SHIELD_BASE}${clubId}.gif" alt="${alt}" onerror="this.style.display='none'"/>`;
}

function posClass(p) { return p === 1 ? "pos-1" : p === 2 ? "pos-2" : p === 3 ? "pos-3" : "pos-n"; }
function posEmoji(p) { return p === 1 ? "🥇" : p === 2 ? "🥈" : p === 3 ? "🥉" : p; }

function resultInfo(hs, as, amHome) {
  if (hs === undefined || as === undefined) return null;
  if (hs === as) return { cls: "draw", badge: "badge-draw", label: "E" };
  const win = amHome ? hs > as : as > hs;
  return win
    ? { cls: "win",  badge: "badge-win",  label: "V" }
    : { cls: "loss", badge: "badge-loss", label: "D" };
}

function escapeHtml(s) {
  return String(s || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
}

// ── Category config ───────────────────────────────────────────
const CAT_CONFIG = {
  "ALL":              { emoji: "🏒", color: "#e5001c" },
  "Nacional Catalana":{ emoji: "👑", color: "#003da5" },
  "1ª Catalana":      { emoji: "⭐", color: "#1a5dc7" },
  "2ª Catalana":      { emoji: "🔵", color: "#2563eb" },
  "3ª Catalana":      { emoji: "🟣", color: "#7c3aed" },
  "Fem":              { emoji: "♀️", color: "#db2777" },
  "Júnior":           { emoji: "🎯", color: "#ea580c" },
  "Juvenil":          { emoji: "⚡", color: "#16a34a" },
  "Infantil":         { emoji: "🏆", color: "#0891b2" },
  "Aleví":            { emoji: "💪", color: "#7c3aed" },
  "Benjamí":          { emoji: "🔥", color: "#dc2626" },
  "Prebenjamí":       { emoji: "⭐", color: "#d97706" },
  "Veterans":         { emoji: "🧓", color: "#6b7280" },
  "Altres":           { emoji: "📋", color: "#6b7280" },
};

// ── Render: Filter tabs ───────────────────────────────────────
function renderFilterTabs() {
  const cats = ["ALL", ...Object.keys(state.data.categories)];
  $filterTabs.innerHTML = cats.map(cat => {
    const cfg = CAT_CONFIG[cat] || { emoji: "📋" };
    const label = cat === "ALL" ? "Totes" : cat;
    const count = cat === "ALL"
      ? Object.values(state.data.categories).reduce((s, v) => s + v.length, 0)
      : (state.data.categories[cat] || []).length;
    return `<button class="filter-btn ${state.activeCategory === cat ? "active" : ""}" data-cat="${cat}">
      ${cfg.emoji} ${label} <span style="font-size:10px;opacity:.6">${count}</span>
    </button>`;
  }).join("");

  $filterTabs.querySelectorAll(".filter-btn").forEach(btn => {
    btn.addEventListener("click", () => {
      state.activeCategory = btn.dataset.cat;
      renderFilterTabs();
      renderPicker();
    });
  });
}

// ── Render: Picker ────────────────────────────────────────────
function renderPicker() {
  const q = state.searchQuery.toLowerCase();

  // Get competitions to show
  let cats = state.activeCategory === "ALL"
    ? Object.entries(state.data.categories)
    : [[state.activeCategory, state.data.categories[state.activeCategory] || []]];

  // Apply search
  if (q) {
    cats = cats.map(([cat, comps]) => [
      cat,
      comps.filter(c =>
        c.name.toLowerCase().includes(q) ||
        c.teams?.some(t => t.name.toLowerCase().includes(q))
      )
    ]).filter(([, comps]) => comps.length > 0);
  }

  if (!cats.length || cats.every(([, c]) => !c.length)) {
    $pickerBody.innerHTML = `<div class="empty-state"><div class="empty-icon">🔍</div><p>Cap competició trobada per "<strong>${escapeHtml(q)}</strong>"</p></div>`;
    return;
  }

  $pickerBody.innerHTML = cats.map(([cat, comps]) => {
    if (!comps.length) return "";
    const cfg = CAT_CONFIG[cat] || { emoji: "📋", color: "#666" };
    return `
      <div class="cat-group fade-up">
        <div class="cat-header">
          <span class="cat-emoji">${cfg.emoji}</span>
          <span class="cat-title" style="color:${cfg.color}">${cat}</span>
          <span class="cat-count">${comps.length}</span>
        </div>
        ${comps.map(comp => renderCompCard(comp, cfg)).join("")}
      </div>`;
  }).join("");

  // Click handlers
  $pickerBody.querySelectorAll(".comp-card").forEach(card => {
    card.addEventListener("click", () => {
      const compId = card.dataset.compId;
      const cat    = card.dataset.cat;
      openComp(state.data.categories[cat]?.find(c => c.id === compId));
    });
  });
}

function renderCompCard(comp, cfg) {
  const pct = comp.pctPlayed ?? 0;
  const teamCount = comp.teams?.length || comp.classification?.length || 0;
  return `
    <div class="comp-card" data-comp-id="${comp.id}" data-cat="${escapeHtml(getCatForComp(comp))}">
      <div class="comp-card-inner">
        <div class="comp-pct">
          <span>${pct ? pct + "%" : "?"}</span>
        </div>
        <div class="comp-info">
          <div class="comp-name">${escapeHtml(comp.name.replace(/\s*\(2025-26\)/, ""))}</div>
          <div class="comp-teams-count">${teamCount} equips</div>
        </div>
        <span class="comp-arrow">›</span>
      </div>
      <div class="comp-progress">
        <div class="comp-progress-bar" style="width:${pct}%"></div>
      </div>
    </div>`;
}

function getCatForComp(comp) {
  for (const [cat, comps] of Object.entries(state.data.categories)) {
    if (comps.some(c => c.id === comp.id)) return cat;
  }
  return "Altres";
}

// ── Open competition ──────────────────────────────────────────
function openComp(comp) {
  if (!comp) return;
  state.selectedComp = comp;
  state.selectedTeam = null;
  state.activeTab    = "summary";

  // Show detail, hide picker
  $picker.style.display = "none";
  $detail.style.display = "flex";

  // Header
  const cleanName = comp.name.replace(/\s*\(2025-26\)/, "");
  $compName.textContent = cleanName;
  $compMeta.textContent = `${comp.teams?.length || comp.classification?.length || 0} equips · ${comp.pctPlayed ?? "?"}% jugat`;

  // Tab state
  document.querySelectorAll(".detail-tab").forEach(t => {
    t.classList.toggle("active", t.dataset.tab === "summary");
  });

  renderDetailPanels();
  window.scrollTo(0, 0);
}

// ── Render detail panels ──────────────────────────────────────
function renderDetailPanels() {
  renderSummary();
  renderClassif();
  renderCalendar();
}

// ── Summary panel ─────────────────────────────────────────────
function renderSummary() {
  const comp = state.selectedComp;
  const cl   = comp.classification || [];

  if (!cl.length) {
    document.getElementById("panel-summary").innerHTML = `
      <div class="empty-state">
        <div class="empty-icon">📊</div>
        <p>Sense dades de classificació.<br/>
        <a href="https://jok.cat/competicio/${comp.id}" target="_blank" rel="noopener">Veure a jok.cat →</a></p>
      </div>`;
    return;
  }

  // Top 3 podium
  const top3 = cl.slice(0, 3);
  const rest  = cl.slice(3);

  // Stats
  const totalGames = cl.reduce((s, r) => s + (r.pj || 0), 0) / 2;
  const totalGoals = cl.reduce((s, r) => s + (r.gf || 0), 0);
  const topScorer  = cl.reduce((a, b) => (b.gf || 0) > (a.gf || 0) ? b : a, cl[0]);

  const html = `
    <!-- Podium -->
    <div style="background:var(--card);border-radius:16px;padding:16px;margin-bottom:14px;box-shadow:var(--shadow)">
      <div class="section-title">Top 3</div>
      ${top3.map((r, i) => {
        const medals = ["🥇","🥈","🥉"];
        const colors = ["#fef3c7","#f1f5f9","#fff7ed"];
        const cid    = getClubIdForTeam(r.team);
        return `<div style="display:flex;align-items:center;gap:10px;padding:10px 0;border-bottom:${i<2?"1px solid var(--border)":"none"}">
          <span style="font-size:20px;width:28px;text-align:center">${medals[i]}</span>
          ${shieldLg(cid, r.team)}
          <div style="flex:1">
            <div style="font-family:var(--font-d);font-size:16px;font-weight:800">${escapeHtml(r.team)}</div>
            <div style="font-size:12px;color:var(--muted)">${r.pj||0} partits · ${r.gf||0} gols a favor</div>
          </div>
          <div style="text-align:right">
            <div style="font-family:var(--font-d);font-size:22px;font-weight:900;color:var(--red)">${r.pts||0}</div>
            <div style="font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.05em">punts</div>
          </div>
        </div>`;
      }).join("")}
    </div>

    <!-- Stats pills -->
    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value" style="color:var(--blue)">${cl.length}</div>
        <div class="stat-label">Equips</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" style="color:var(--red)">${Math.round(totalGames)}</div>
        <div class="stat-label">Partits</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" style="color:var(--gold)">${totalGoals}</div>
        <div class="stat-label">Gols</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" style="color:#16a34a">${comp.pctPlayed ?? "?"}%</div>
        <div class="stat-label">Jugat</div>
      </div>
    </div>

    <div class="update-box">
      <span style="font-size:18px">💡</span>
      <p>Dades actualitzades el <strong>${formatDate(state.data.updatedAt)}</strong>.
      Veure totes les dades a <a href="https://jok.cat/competicio/${comp.id}" target="_blank" rel="noopener" style="color:var(--blue);font-weight:600">jok.cat →</a></p>
    </div>`;

  document.getElementById("panel-summary").innerHTML = html;
}

// ── Classification panel ──────────────────────────────────────
function renderClassif() {
  const comp = state.selectedComp;
  const cl   = comp.classification || [];

  if (!cl.length) {
    document.getElementById("panel-classif").innerHTML = `
      <div class="empty-state">
        <div class="empty-icon">📋</div>
        <p>Classificació no disponible.<br/>
        <a href="https://jok.cat/competicio/${comp.id}" target="_blank" rel="noopener">Veure a jok.cat →</a></p>
      </div>`;
    return;
  }

  const rows = cl.map(r => {
    const cid    = getClubIdForTeam(r.team);
    const isMyT  = state.selectedTeam && r.team === state.selectedTeam;
    return `<tr class="${isMyT ? "my-team" : ""}">
      <td><span class="pos-badge ${posClass(r.pos)}">${posEmoji(r.pos)}</span></td>
      <td>
        <div class="team-name-cell">
          ${shield(cid, r.team)}
          <span>${escapeHtml(r.team)}</span>
          ${isMyT ? '<span class="my-team-arrow">◀</span>' : ""}
        </div>
      </td>
      <td>${r.pj ?? "-"}</td>
      <td style="color:#16a34a;font-weight:600">${r.pg ?? "-"}</td>
      <td style="color:#d97706">${r.pe ?? "-"}</td>
      <td style="color:#dc2626">${r.pp ?? "-"}</td>
      <td>${r.gf ?? "-"}</td>
      <td>${r.gc ?? "-"}</td>
      <td style="font-weight:800;color:var(--red)">${r.pts ?? "-"}</td>
    </tr>`;
  }).join("");

  document.getElementById("panel-classif").innerHTML = `
    <div class="classif-wrap">
      <table class="classif-table">
        <thead><tr>
          <th>#</th><th style="text-align:left">Equip</th>
          <th>PJ</th><th>PG</th><th>PE</th><th>PP</th>
          <th>GF</th><th>GC</th><th>Pts</th>
        </tr></thead>
        <tbody>${rows}</tbody>
      </table>
    </div>`;
}

// ── Calendar panel ────────────────────────────────────────────
function renderCalendar() {
  const comp    = state.selectedComp;
  let matches   = comp.calendar || [];

  if (!matches.length) {
    document.getElementById("panel-calendar").innerHTML = `
      <div class="empty-state">
        <div class="empty-icon">📅</div>
        <p>Calendari no disponible.<br/>
        <a href="https://jok.cat/competicio/${comp.id}" target="_blank" rel="noopener">Veure a jok.cat →</a></p>
      </div>`;
    return;
  }

  // Team filter chips
  const teamNames = [...new Set([
    ...matches.map(m => m.home),
    ...matches.map(m => m.away),
  ])].filter(Boolean).sort();

  const chips = teamNames.map(t => {
    const cid = getClubIdForTeam(t);
    const act = state.selectedTeam === t;
    return `<div class="team-chip ${act?"active":""}" data-team="${escapeHtml(t)}">
      <img src="${SHIELD_BASE}${cid||"0"}.gif" style="width:18px;height:18px;object-fit:contain" onerror="this.style.display='none'" alt=""/>
      ${escapeHtml(t.replace("Club Hoquei ","").replace("CH ","").replace("Cp ",""))}
    </div>`;
  }).join("");

  // Filter if team selected
  if (state.selectedTeam) {
    matches = matches.filter(m =>
      m.home === state.selectedTeam || m.away === state.selectedTeam
    );
  }

  // Group by jornada
  const byJornada = {};
  matches.forEach(m => {
    const key = m.jornada ? `Jornada ${m.jornada}` : m.date || "?";
    if (!byJornada[key]) byJornada[key] = [];
    byJornada[key].push(m);
  });

  const matchHTML = Object.entries(byJornada).map(([jornada, ms]) => `
    <div class="cal-section">
      <div class="cal-jornada-label">${jornada}</div>
      ${ms.map(m => renderMatchCard(m)).join("")}
    </div>
  `).join("");

  const legendHTML = `
    <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px">
      ${[["badge-win","V Victòria"],["badge-draw","E Empat"],["badge-loss","D Derrota"]].map(
        ([cls,l]) => `<span class="match-result-badge ${cls}">${l}</span>`
      ).join("")}
    </div>`;

  document.getElementById("panel-calendar").innerHTML = `
    <div class="team-filter-wrap">
      <div class="team-filter-label">Filtrar per equip</div>
      <div class="team-chips" id="team-chips">${chips}</div>
    </div>
    ${state.selectedTeam ? legendHTML : ""}
    ${matchHTML}`;

  // Team chip click
  document.getElementById("team-chips").querySelectorAll(".team-chip").forEach(chip => {
    chip.addEventListener("click", () => {
      const t = chip.dataset.team;
      state.selectedTeam = state.selectedTeam === t ? null : t;
      renderCalendar();
    });
  });
}

function renderMatchCard(m) {
  const played = m.played !== false && m.homeScore !== undefined;
  const homeCid = getClubIdForTeam(m.home);
  const awayCid = getClubIdForTeam(m.away);

  let resultBadge = "";
  let cardCls     = "match-card " + (played ? "" : "pending");

  if (played && state.selectedTeam) {
    const amHome = m.home === state.selectedTeam;
    const res = resultInfo(m.homeScore, m.awayScore, amHome);
    if (res) {
      cardCls = `match-card played ${res.cls}`;
      resultBadge = `<div style="text-align:center;margin-top:6px"><span class="match-result-badge ${res.badge}">${res.label}</span></div>`;
    }
  }

  const homeHL = state.selectedTeam === m.home ? "highlighted" : "";
  const awayHL = state.selectedTeam === m.away ? "highlighted" : "";

  const scoreBlock = played
    ? `<div class="match-score-block">
        <div class="match-score">${m.homeScore} – ${m.awayScore}</div>
        <div class="match-date">${m.date || ""}</div>
      </div>`
    : `<div class="match-score-block">
        <div class="match-score pending">VS</div>
        <div class="match-date">${m.date || ""}${m.time ? " · " + m.time : ""}</div>
      </div>`;

  return `<div class="${cardCls}">
    <div class="match-teams">
      <div class="match-team">
        <img class="match-team-shield" src="${SHIELD_BASE}${homeCid||"0"}.gif" onerror="this.style.display='none'" alt=""/>
        <span class="match-team-name ${homeHL}">${escapeHtml(m.home)}</span>
      </div>
      ${scoreBlock}
      <div class="match-team right">
        <img class="match-team-shield" src="${SHIELD_BASE}${awayCid||"0"}.gif" onerror="this.style.display='none'" alt=""/>
        <span class="match-team-name ${awayHL}">${escapeHtml(m.away)}</span>
      </div>
    </div>
    ${resultBadge}
  </div>`;
}

// ── Club ID lookup ────────────────────────────────────────────
// Build a name→clubId map from all competition data
let _nameToClubId = null;

function buildNameToClubId() {
  if (_nameToClubId) return;
  _nameToClubId = {};
  for (const comps of Object.values(state.data.categories)) {
    for (const comp of comps) {
      // Try to map team names to clubIds from classification + calendar
      if (comp.clubIds?.length && comp.teams?.length) {
        // Rough mapping: assume each team has one clubId (many teams = many clubIds)
        comp.teams.forEach((t, i) => {
          if (comp.clubIds[i]) _nameToClubId[t.name] = comp.clubIds[i];
        });
      }
    }
  }
}

function getClubIdForTeam(teamName) {
  if (!teamName) return null;
  buildNameToClubId();
  // Direct match
  if (_nameToClubId[teamName]) return _nameToClubId[teamName];
  // Fuzzy: strip trailing A/B/C
  const base = teamName.replace(/\s+[A-D]$/, "").trim();
  for (const [k, v] of Object.entries(_nameToClubId)) {
    if (k.toLowerCase().includes(base.toLowerCase())) return v;
  }
  return null;
}

// ── Date formatting ───────────────────────────────────────────
function formatDate(iso) {
  if (!iso) return "?";
  const d = new Date(iso);
  return d.toLocaleDateString("ca-ES", { day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" });
}

// ── Tab switching ─────────────────────────────────────────────
document.querySelectorAll(".detail-tab").forEach(tab => {
  tab.addEventListener("click", () => {
    state.activeTab = tab.dataset.tab;
    document.querySelectorAll(".detail-tab").forEach(t => t.classList.toggle("active", t === tab));
    document.querySelectorAll(".panel").forEach(p => p.classList.toggle("active", p.id === `panel-${state.activeTab}`));
  });
});

// ── Back button ───────────────────────────────────────────────
$backBtn.addEventListener("click", () => {
  $detail.style.display  = "none";
  $picker.style.display  = "flex";
  state.selectedComp     = null;
  window.scrollTo(0, 0);
});

// ── Search ────────────────────────────────────────────────────
$searchInput.addEventListener("input", () => {
  state.searchQuery = $searchInput.value;
  renderPicker();
});

// ── Init ─────────────────────────────────────────────────────
async function init() {
  try {
    $loadingNote.textContent = "Carregant dades de FECAPA...";
    const res  = await fetch(DATA_URL + "?t=" + Date.now());
    if (!res.ok) throw new Error("No s'han pogut carregar les dades");
    state.data = await res.json();

    $heroSeason.textContent = state.data.season || "2025-26";
    const total = state.data.totalComps || 0;
    $heroSub.textContent = `${total} competicions · Actualitzat ${formatDate(state.data.updatedAt)}`;

    $loading.style.display = "none";
    $picker.style.display  = "flex";
    renderFilterTabs();
    renderPicker();

  } catch (err) {
    $loadingNote.innerHTML = `
      <span style="color:#e5001c">⚠️ ${err.message}</span><br/>
      <small>Assegura't d'executar el scraper primer: <code>node api/scraper.js</code></small>`;
  }
}

init();
